import{_ as e,o,c as d,a2 as a}from"./chunks/framework.DeNJmwJc.js";const m=JSON.parse('{"title":"Chapter 10 — Motions","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/10-motions.md","filePath":"chapters/10-motions.md"}'),n={name:"chapters/10-motions.md"};function i(r,t,s,c,l,h){return o(),d("div",null,[...t[0]||(t[0]=[a(`<h1 id="chapter-10-—-motions" tabindex="-1">Chapter 10 — Motions <a class="header-anchor" href="#chapter-10-—-motions" aria-label="Permalink to &quot;Chapter 10 — Motions&quot;">​</a></h1><blockquote><p><em>&quot;Motions are the verbs in Vim&#39;s editing language.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 20–25 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>In the previous chapter, you learned how to move the cursor.</p><p>But in Vim, movement keys are not just for navigation.</p><p>They are <strong>motions</strong>—and motions can be combined with <strong>operators</strong> to perform powerful edits.</p><hr><h1 id="what-is-a-motion" tabindex="-1">What Is a Motion? <a class="header-anchor" href="#what-is-a-motion" aria-label="Permalink to &quot;What Is a Motion?&quot;">​</a></h1><p>A <strong>motion</strong> is a command that moves the cursor.</p><p>Every movement key you learned is a motion:</p><ul><li><code>w</code> — move to next word (motion)</li><li><code>j</code> — move down one line (motion)</li><li><code>$</code> — move to end of line (motion)</li><li><code>G</code> — move to end of file (motion)</li></ul><p>But motions alone are just the beginning.</p><hr><h1 id="the-key-insight" tabindex="-1">The Key Insight <a class="header-anchor" href="#the-key-insight" aria-label="Permalink to &quot;The Key Insight&quot;">​</a></h1><p>In Vim, you can combine an <strong>operator</strong> + <strong>motion</strong> to act on the text between the cursor and the destination.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Operator   +   Motion   =   Action</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   d       +     w      =   dw  (delete word)</span></span>
<span class="line"><span>   c       +     $      =   c$  (change to end of line)</span></span>
<span class="line"><span>   y       +     j      =   yj  (yank current + next line)</span></span></code></pre></div><p>This is the grammar that makes Vim powerful.</p><hr><h1 id="common-operators" tabindex="-1">Common Operators <a class="header-anchor" href="#common-operators" aria-label="Permalink to &quot;Common Operators&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Operator</th><th>Action</th></tr></thead><tbody><tr><td><code>d</code></td><td>Delete</td></tr><tr><td><code>c</code></td><td>Change (delete + insert)</td></tr><tr><td><code>y</code></td><td>Yank (copy)</td></tr><tr><td><code>v</code></td><td>Character-wise visual</td></tr><tr><td><code>g~</code></td><td>Swap case</td></tr><tr><td><code>gu</code></td><td>Make lowercase</td></tr><tr><td><code>gU</code></td><td>Make uppercase</td></tr><tr><td><code>&gt;</code></td><td>Indent right</td></tr><tr><td><code>&lt;</code></td><td>Indent left</td></tr><tr><td><code>=</code></td><td>Auto-indent</td></tr></tbody></table><hr><h1 id="operator-motion-examples" tabindex="-1">Operator + Motion Examples <a class="header-anchor" href="#operator-motion-examples" aria-label="Permalink to &quot;Operator + Motion Examples&quot;">​</a></h1><h2 id="delete" tabindex="-1">Delete <a class="header-anchor" href="#delete" aria-label="Permalink to &quot;Delete&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>dw</code></td><td>Delete from cursor to next word</td></tr><tr><td><code>d3w</code></td><td>Delete next 3 words</td></tr><tr><td><code>db</code></td><td>Delete backward to beginning of word</td></tr><tr><td><code>d$</code></td><td>Delete to end of line</td></tr><tr><td><code>d0</code></td><td>Delete to beginning of line</td></tr><tr><td><code>dG</code></td><td>Delete from cursor to end of file</td></tr><tr><td><code>dgg</code></td><td>Delete from cursor to beginning</td></tr><tr><td><code>d10j</code></td><td>Delete current line and 10 lines down</td></tr></tbody></table><h2 id="change" tabindex="-1">Change <a class="header-anchor" href="#change" aria-label="Permalink to &quot;Change&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>cw</code></td><td>Change word (delete word + insert)</td></tr><tr><td><code>c$</code></td><td>Change to end of line</td></tr><tr><td><code>c0</code></td><td>Change to beginning of line</td></tr><tr><td><code>c3w</code></td><td>Change next 3 words</td></tr><tr><td><code>cG</code></td><td>Change to end of file</td></tr></tbody></table><h2 id="yank-copy" tabindex="-1">Yank (Copy) <a class="header-anchor" href="#yank-copy" aria-label="Permalink to &quot;Yank (Copy)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>yw</code></td><td>Yank word</td></tr><tr><td><code>y$</code></td><td>Yank to end of line</td></tr><tr><td><code>y0</code></td><td>Yank to beginning of line</td></tr><tr><td><code>y3w</code></td><td>Yank next 3 words</td></tr><tr><td><code>yG</code></td><td>Yank from cursor to end of file</td></tr><tr><td><code>ygg</code></td><td>Yank from cursor to beginning</td></tr></tbody></table><hr><h1 id="motion-types" tabindex="-1">Motion Types <a class="header-anchor" href="#motion-types" aria-label="Permalink to &quot;Motion Types&quot;">​</a></h1><p>Motions can be:</p><table tabindex="0"><thead><tr><th>Category</th><th>Examples</th><th>Description</th></tr></thead><tbody><tr><td>Character</td><td><code>h</code>, <code>j</code>, <code>k</code>, <code>l</code></td><td>Basic cursor movement</td></tr><tr><td>Word</td><td><code>w</code>, <code>b</code>, <code>e</code></td><td>Word-based movement</td></tr><tr><td>Line</td><td><code>0</code>, <code>$</code>, <code>^</code>, <code>g_</code></td><td>Line-boundary movement</td></tr><tr><td>File</td><td><code>gg</code>, <code>G</code>, <code>H</code>, <code>L</code></td><td>File-level movement</td></tr><tr><td>Search</td><td><code>f</code>, <code>F</code>, <code>t</code>, <code>T</code></td><td>Character search</td></tr><tr><td>Text object</td><td><code>iw</code>, <code>ip</code>, <code>i(</code>, <code>i&quot;</code></td><td>Structural elements</td></tr></tbody></table><hr><h1 id="inclusive-vs-exclusive-motions" tabindex="-1">Inclusive vs Exclusive Motions <a class="header-anchor" href="#inclusive-vs-exclusive-motions" aria-label="Permalink to &quot;Inclusive vs Exclusive Motions&quot;">​</a></h1><p>Some motions are <strong>inclusive</strong> (include the character under the cursor).</p><p>Some are <strong>exclusive</strong> (stop before the character).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>d$  →  deletes from cursor to end of line (inclusive of last char)</span></span>
<span class="line"><span>dw  →  deletes from cursor to start of next word (exclusive of first char of next word)</span></span></code></pre></div><p>You don&#39;t need to memorize this—just be aware it exists.</p><hr><h1 id="compound-example" tabindex="-1">Compound Example <a class="header-anchor" href="#compound-example" aria-label="Permalink to &quot;Compound Example&quot;">​</a></h1><p>Let&#39;s see how motions combine with operators in practice.</p><p>File content:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> calculate_total</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(items):</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    total </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> item </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> items:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        total </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> item.price</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> total</span></span></code></pre></div><table tabindex="0"><thead><tr><th>If cursor is on...</th><th>You type</th><th>Result</th></tr></thead><tbody><tr><td>Line 3, column 10</td><td><code>d$</code></td><td>Deletes rest of line</td></tr><tr><td><code>items</code> on line 1</td><td><code>ci(</code></td><td>Changes parentheses content</td></tr><tr><td>Line 2</td><td><code>dd</code></td><td>Deletes whole line</td></tr><tr><td><code>total</code> on line 2</td><td><code>yiw</code></td><td>Copies word <code>total</code></td></tr><tr><td>Anywhere</td><td><code>gg</code></td><td>Jumps to line 1</td></tr></tbody></table><hr><h1 id="the-dot-command-and-motions" tabindex="-1">The Dot Command and Motions <a class="header-anchor" href="#the-dot-command-and-motions" aria-label="Permalink to &quot;The Dot Command and Motions&quot;">​</a></h1><p>The dot (<code>.</code>) repeats the <strong>last change</strong>.</p><p>If you delete a word with <code>dw</code>, then press <code>.</code>, it deletes the next word.</p><p>If you change inside quotes with <code>ci&quot;</code>, then press <code>.</code> somewhere else inside quotes, it repeats the change.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li>A <strong>motion</strong> moves the cursor.</li><li>An <strong>operator</strong> performs an action.</li><li><strong>Operator + Motion</strong> = Powerful editing command.</li><li>Common operators: <code>d</code> (delete), <code>c</code> (change), <code>y</code> (yank).</li><li>Most movement keys can serve as motions.</li><li>The dot command repeats the last operator+motion combo.</li></ul><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li>Vim&#39;s power comes from composing operators with motions.</li><li><code>dw</code>, <code>c$</code>, <code>yG</code> — learn to think in this pattern.</li><li>Almost every movement can be combined with an operator.</li><li>Practice the combinations; they will become automatic.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a file and practice: <code>dw</code>, <code>d3w</code>, <code>d$</code>, <code>d0</code>, <code>dG</code>.</li><li>Practice change: <code>cw</code>, <code>c$</code>, <code>c3w</code>.</li><li>Practice yank: <code>yw</code>, <code>y$</code>, <code>yG</code>.</li><li>Combine with counts: <code>d5w</code>, <code>c2$</code>, <code>y10j</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./11-word-motions.html"><strong>Chapter 11 — Word Motions</strong></a></p><p>Master word-level navigation—the motions you&#39;ll use most frequently.</p>`,65)])])}const u=e(n,[["render",i]]);export{m as __pageData,u as default};
